def test_health(client):
    response = client.get("/health", headers={"Host": "testserver"})
    assert response.status_code == 200
    assert response.get_json()["status"] == "ok"


def test_create_run_and_fetch(client, benchmark_payload):
    create_response = client.post(
        "/api/v1/benchmarks/run",
        json=benchmark_payload,
        headers={"Host": "testserver"},
    )
    assert create_response.status_code == 201
    run_data = create_response.get_json()
    assert run_data["case_count"] == 2
    assert run_data["mrr"] > 0

    list_response = client.get("/api/v1/benchmarks/runs", headers={"Host": "testserver"})
    assert list_response.status_code == 200
    assert len(list_response.get_json()["runs"]) == 1

    run_response = client.get(
        f"/api/v1/benchmarks/runs/{run_data['run_id']}",
        headers={"Host": "testserver"},
    )
    assert run_response.status_code == 200
    assert run_response.get_json()["run_id"] == run_data["run_id"]


def test_validation_error_for_missing_cases(client):
    response = client.post(
        "/api/v1/benchmarks/run",
        json={"name": "bad", "retriever": "faiss", "generator": "gpt", "k": 2},
        headers={"Host": "testserver"},
    )

    assert response.status_code == 400
    assert response.get_json()["error"] == "validation_error"


def test_host_rejected(client):
    response = client.get("/health", headers={"Host": "blocked.example"})
    assert response.status_code == 400
    assert response.get_json()["error"] == "host_not_allowed"
